+    #[test]
+    fn drift_enabled_but_stopped() {
+        let state = ConnectorAdminState {
+            lifecycle: None,
+            desired_state: DesiredRuntimeState::Enabled,
+            observed_state: ObservedRuntimeState::Stopped,
+            pinned_version: None,
+            config_revisions: Vec::new(),
+            active_config_revision_id: None,
